const input = $input.first().json;
const topic = (input.topic || input.query || '').toLowerCase();
const history = [
  { date: '2026-04-15', topic: 'bosch api documentation', occurrences: 1, impact: 'Firmware integration blocked 2 weeks' },
  { date: '2026-05-01', topic: 'bosch api documentation delay', occurrences: 2, impact: 'Integration testing delayed, sprint missed' },
  { date: '2026-04-08', topic: 'imu sensor calibration drift', occurrences: 1, impact: 'Precision targeting off by 3.1mm' },
  { date: '2026-05-15', topic: 'sensor calibration imu drift', occurrences: 1, impact: 'Precision targeting off by 2.8mm' },
  { date: '2026-05-20', topic: 'power consumption regression', occurrences: 1, impact: 'Build 2.3 exceeded 280W power budget' }
];
const matches = history.filter(h => { const words = topic.split(' '); return words.some(w => w.length > 3 && h.topic.includes(w)); });
if (matches.length > 0) {
  const total = matches.reduce((s, m) => s + m.occurrences, 0) + 1;
  return JSON.stringify({ is_recurring: true, total_occurrences: total, first_seen: matches[matches.length - 1].date, last_seen: matches[0].date, pattern: 'RECURRING BLOCKER seen ' + total + ' times in 2 months', historical_impact: matches.map(m => m.impact).join(' | '), recommendation: 'Escalation recommended' });
}
return JSON.stringify({ is_recurring: false, total_occurrences: 1, pattern: 'First occurrence', recommendation: 'Monitor' });

const raw = $input.first().json;
const d = typeof raw === 'string' ? JSON.parse(raw) : raw;
const title = d.title || 'Integration Review Follow-up';
const start = d.start_datetime || '2026-06-13T09:00:00';
const end = d.end_datetime || '2026-06-13T10:00:00';
const agenda = d.agenda || 'Review integration progress';
return JSON.stringify({
  success: true,
  status: 'Meeting queued: ' + title + ' on ' + start.split('T')[0],
  title: title,
  start_datetime: start,
  end_datetime: end,
  agenda: agenda,
  note: 'Calendar event will be created via Graph API'
});

const raw = $input.first().json;
const d = typeof raw === 'string' ? JSON.parse(raw) : raw;
const name = d.recipient_name || d.owner_name || 'Team Member';
const email = d.recipient_email || d.owner_email || 'unknown';
const task = d.task || 'Action item';
const deadline = d.deadline || 'TBD';
const priority = (d.priority || 'medium').toUpperCase();
return JSON.stringify({
  success: true,
  status: 'Email queued for ' + name,
  recipient: name,
  email: email,
  task: task,
  deadline: deadline,
  priority: priority,
  note: 'Email will be sent via Graph API'
});

const raw = $input.first().json.output || '';
let parsed;
try {
  let text = typeof raw === 'string' ? raw : JSON.stringify(raw);
  text = text.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    parsed = JSON.parse(text.slice(start, end + 1));
  } else { throw new Error('No JSON found'); }
} catch (e) {
  parsed = { meeting_summary: 'Parse error', action_items: [], external_participants_detected: false, blockers: [], follow_up_meeting: null, risk_flags: ['Parse error: ' + e.message] };
}
return [{ json: parsed }];

const data = $input.first().json;
const items = data.action_items || [];
if (items.length === 0) return [{ json: { status: 'no_action_items' } }];
return items.map(item => ({ json: item }));

const data = $input.first().json;
const items = data.action_items || [];
const followup = data.follow_up_meeting || null;
const meeting = data.meeting_summary ? 'this meeting' : 'Robot Arm Integration Sync';
const followupDate = followup ? followup.date + ' at ' + followup.time : 'TBD';
const actionEmails = items.map((item, i) => ({
  email_number: i + 1,
  type: 'Action Item Email',
  to: item.owner_email,
  recipient: item.owner_name,
  subject: '[Action Required] ' + item.task + ' due ' + item.deadline,
  body: 'Hi ' + item.owner_name + ',\n\nTask: ' + item.task + '\nDeadline: ' + item.deadline + '\nPriority: ' + (item.priority || 'medium').toUpperCase() + (item.depends_on ? '\nDepends on: ' + item.depends_on : '') + '\n\nFollow-up: ' + followupDate + '\n\n- NEURA AI Meeting Agent'
}));
const inviteEmail = followup ? {
  email_number: items.length + 1,
  type: 'Follow-up Meeting Invite',
  to: followup.attendees,
  subject: 'Meeting Invite: ' + followup.title + ' ' + followup.date,
  body: 'Follow-up meeting: ' + followup.title + ' on ' + followup.date + ' at ' + followup.time + '.\nAgenda: ' + followup.agenda
} : null;
const all = inviteEmail ? [...actionEmails, inviteEmail] : actionEmails;
return all.map(e => ({ json: e }));
